mapper.select:
SELECT a.action_log_id, a.target_type, a.target_id, a.admin_id, u.name AS adminName, a.action_type, a.reason, a.created_at, s.monthly, s.workshop_id, CASE a.target_type WHEN 'WORKSHOP' THEN w.name WHEN 'PROGRAM' THEN p.title WHEN 'QNA' THEN qu.name WHEN 'SETTLEMENT' THEN sw.name END AS targetName FROM action_log a JOIN user u ON a.admin_id = u.user_id LEFT JOIN workshop w ON a.target_id = w.workshop_id AND a.target_type = 'WORKSHOP' LEFT JOIN program p ON a.target_id = p.program_id AND a.target_type = 'PROGRAM' LEFT JOIN qna_admin q ON a.target_id = q.qna_admin_id AND a.target_type = 'QNA' LEFT JOIN user qu ON q.user_id = qu.user_id AND a.target_type = 'QNA' LEFT JOIN settlement s ON a.target_id = s.settlement_id AND a.target_type = 'SETTLEMENT' LEFT JOIN workshop sw ON s.workshop_id = sw.workshop_id
AND a.target_type = #{targetType}
AND ( u.name LIKE CONCAT('%', #{keyword}, '%') OR w.name LIKE CONCAT('%', #{keyword}, '%') OR p.title LIKE CONCAT('%', #{keyword}, '%') OR qu.name LIKE CONCAT('%', #{keyword}, '%') OR sw.name LIKE CONCAT('%', #{keyword}, '%') OR a.action_type LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY a.created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM action_log a JOIN user u ON a.admin_id = u.user_id LEFT JOIN workshop w ON a.target_id = w.workshop_id AND a.target_type = 'WORKSHOP' LEFT JOIN program p ON a.target_id = p.program_id AND a.target_type = 'PROGRAM' LEFT JOIN qna_admin q ON a.target_id = q.qna_admin_id AND a.target_type = 'QNA' LEFT JOIN user qu ON q.user_id = qu.user_id AND a.target_type = 'QNA' LEFT JOIN settlement s ON a.target_id = s.settlement_id AND a.target_type = 'SETTLEMENT' LEFT JOIN workshop sw ON s.workshop_id = sw.workshop_id
AND a.target_type = #{targetType}
AND ( u.name LIKE CONCAT('%', #{keyword}, '%') OR w.name LIKE CONCAT('%', #{keyword}, '%') OR p.title LIKE CONCAT('%', #{keyword}, '%') OR qu.name LIKE CONCAT('%', #{keyword}, '%') OR sw.name LIKE CONCAT('%', #{keyword}, '%') OR a.action_type LIKE CONCAT('%', #{keyword}, '%') )

SELECT a.action_log_id, a.target_type, a.target_id, a.admin_id, u.name AS adminName, a.action_type, a.reason, a.created_at, CASE a.target_type WHEN 'WORKSHOP' THEN w.name WHEN 'PROGRAM' THEN p.title END AS targetName, CASE a.target_type WHEN 'PROGRAM' THEN ws.name ELSE NULL END AS workshopName FROM action_log a JOIN user u ON a.admin_id = u.user_id LEFT JOIN workshop w ON a.target_id = w.workshop_id AND a.target_type = 'WORKSHOP' LEFT JOIN program p ON a.target_id = p.program_id AND a.target_type = 'PROGRAM' LEFT JOIN workshop ws ON p.workshop_id = ws.workshop_id AND a.target_type = 'PROGRAM'
a.target_type IN ('WORKSHOP', 'PROGRAM')
a.target_type = 'WORKSHOP'
a.target_type = 'PROGRAM'
AND a.action_type = #{filter}
AND (w.name LIKE CONCAT('%', #{keyword}, '%') OR p.title LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY
${sortBy} ${sortDir}
a.created_at DESC
LIMIT #{size} OFFSET #{offset}
